		}
		if i == current {
			labelParts = append(labelParts, stepActiveStyle.Render(label))
		} else {
			labelParts = append(labelParts, stepPendingStyle.Render(label))
		}
	}

	return lipgloss.JoinVertical(
		lipgloss.Left,
		strings.Join(dots, " "),
		strings.Join(labelParts, "   "),
	)
}

