			for _, h := range s.SelectedHarness {
				configs = append(configs, harness.AgentConfig{
					Role:        a.Role,
					Harness:     h,
					Model:       a.Model,
					Effort:      a.Effort,
					Enabled:     a.Enabled,
					Temperature: parseTemperature(a.Temperature),
				})
			}
			continue
		}
		configs = append(configs, harness.AgentConfig{
			Role:        a.Role,
			Harness:     a.Harness,
			Model:       a.Model,
			Effort:      a.Effort,
			Enabled:     a.Enabled,
			Temperature: parseTemperature(a.Temperature),
		})
	}
	return configs
}

