			for i := len(m.allInstances) - 1; i >= 0; i-- {
				if m.allInstances[i].TaskFile == planFile {
					_ = m.allInstances[i].Kill()
					m.allInstances = append(m.allInstances[:i], m.allInstances[i+1:]...)
				}
