			// Walk through FSM to done if not already there.
			if taskfsm.Status(entry.Status) != taskfsm.StatusDone {
				if taskfsm.Status(entry.Status) != taskfsm.StatusReviewing {
					if err := m.fsmSetReviewing(planFile); err != nil {
